#include <stdio.h>
#include <stdlib.h>

int main() {
    int *ptr = (int*)malloc(sizeof(int));
    if (ptr != NULL) {
        *ptr = 100;
        printf("Value: %d\n", *ptr);
        free(ptr);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int *arr = (int*)calloc(5, sizeof(int));
    if (arr != NULL) {
        for(int i=0; i<5; i++) printf("%d ", arr[i]);
        free(arr);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int *ptr = malloc(2 * sizeof(int));
    // ... use ptr ...
    int *new_ptr = realloc(ptr, 5 * sizeof(int));
    if (new_ptr != NULL) {
        ptr = new_ptr;
        // ptr now points to size 5 block
    }
    free(ptr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int n;
    printf("Enter number of elements: ");
    scanf("%d", &n);
    int *arr = (int*)malloc(n * sizeof(int));
    if (arr != NULL) {
        for (int i = 0; i < n; i++) arr[i] = i + 1;
        // ... process arr ...
        free(arr);
    }
    return 0;
}

